// Parse PWA FormData into workflow format
const inputItem = $input.first();
const json = inputItem.json;
const body = json.body || json;
const binary = inputItem.binary || {};
const items = [];

// Extract form fields - check both json root and json.body
const sales_person_name = body['Sales Person Name'] || json['Sales Person Name'] || json.salesPerson || '';
const remark = body['Remark'] || json['Remark'] || json.remark || '';
const event_name = body['Event Name'] || json['Event Name'] || json.eventName || '';
const quick_notes = body['Quick Notes'] || json['Quick Notes'] || json.quickNotes || '';

// Find images and voice note from binary data
const frontImages = {};
const backImages = {};
let voiceNote = null;
let frontIdx = 0;
let backIdx = 0;

for (const key of Object.keys(binary)) {
  const k = key.toLowerCase();
  if (k.includes('business_card_image') || k.includes('business card image') || (k.includes('front') && !k.includes('back'))) {
    frontImages[String(frontIdx)] = binary[key];
    frontIdx++;
  } else if (k.includes('back') || k.includes('business_card_back')) {
    backImages[String(backIdx)] = binary[key];
    backIdx++;
  } else if (k.includes('voice') || k.includes('audio')) {
    voiceNote = binary[key];
  }
}

// If no categorized images found, try generic binary keys
if (frontIdx === 0) {
  for (const key of Object.keys(binary)) {
    if (!key.toLowerCase().includes('voice') && !key.toLowerCase().includes('audio')) {
      frontImages[String(frontIdx)] = binary[key];
      frontIdx++;
    }
  }
}

for (const index of Object.keys(frontImages)) {
  const item = {
    json: {
      sales_person_name: sales_person_name,
      remark: remark,
      event_name: event_name,
      quick_notes: quick_notes,
      has_voice_note: voiceNote ? true : false
    },
    binary: {
      Business_Card_Image: frontImages[index]
    }
  };
  if (backImages[index]) {
    item.binary.Business_Card_Back_Side = backImages[index];
  }
  if (voiceNote && index === '0') {
    item.binary.Voice_Note = voiceNote;
  }
  items.push(item);
}

if (items.length === 0) {
  return [{ json: { sales_person_name, remark, event_name, quick_notes, has_voice_note: false }, binary }];
}

return items;

// Split multiple card uploads into individual items
// Also handle voice notes and extra form fields

const inputItem = $input.first();
const json = inputItem.json;
const binary = inputItem.binary || {};
const items = [];

// Extract form fields
const sales_person_name = json['Sales Person Name'] || '';
const remark = json.Remark || '';
const event_name = json['Event Name'] || '';
const quick_notes = json['Quick Notes'] || '';

// Separate front images, back images, and voice notes
const frontImages = {};
const backImages = {};
let voiceNote = null;

for (const key of Object.keys(binary)) {
  if (key.startsWith('Business_Card_Image_')) {
    const index = key.replace('Business_Card_Image_', '');
    frontImages[index] = binary[key];
  } else if (key.startsWith('Business_Card_Back_Side_Optional_')) {
    const index = key.replace('Business_Card_Back_Side_Optional_', '');
    backImages[index] = binary[key];
  } else if (key.startsWith('Voice_Note_Optional_') || key.startsWith('Voice_Note_')) {
    voiceNote = binary[key];
  }
}

// Process each front image and match with corresponding back image
for (const index of Object.keys(frontImages)) {
  const item = {
    json: {
      sales_person_name: sales_person_name,
      remark: remark,
      event_name: event_name,
      quick_notes: quick_notes,
      has_voice_note: voiceNote ? true : false
    },
    binary: {
      Business_Card_Image: frontImages[index]
    }
  };

  // Add back side image if exists for this index
  if (backImages[index]) {
    item.binary.Business_Card_Back_Side = backImages[index];
  }

  // Add voice note to first card item only
  if (voiceNote && index === Object.keys(frontImages)[0]) {
    item.binary.Voice_Note = voiceNote;
  }

  items.push(item);
}

if (items.length === 0) {
  return [inputItem];
}

return items;

