const items = $input.all();
const processedItems = [];

const cleanNumbers = (val) => {
  if (!val) return '';
  return String(val).replace(/[^0-9,+\s-]/g, '').replace(/\+91/g, '').replace(/[\s-]/g, '').replace(/,+/g, ',').split(',').map(n => n.trim()).filter(n => n.length >= 5 && n.length <= 15).join(', ');
};

// Get form data from ALL possible sources
let sales_person_name = '', remark = '', event_name = '', quick_notes = '';
const sources = ['Parse PWA Data', 'Split Cards & Extract Voice', 'Workflow Configuration', 'Prepare Card Data'];
for (const src of sources) {
  try {
    const d = $(src).first().json;
    if (!sales_person_name && d.sales_person_name) sales_person_name = d.sales_person_name;
    if (!remark && d.remark) remark = d.remark;
    if (!event_name && d.event_name) event_name = d.event_name;
    if (!quick_notes && d.quick_notes) quick_notes = d.quick_notes;
  } catch (e) {}
}

// Get voice note
let voice_note_text = '';
try {
  const v = $('Transcribe Voice Note');
  if (v && v.first()) voice_note_text = v.first().json.text || v.first().json.transcription || '';
} catch (e) {}

for (const item of items) {
  const output = item.json.output || item.json;
  if (output.phone_number) output.phone_number = cleanNumbers(output.phone_number);
  if (output.mobile_number) output.mobile_number = cleanNumbers(output.mobile_number);

  processedItems.push({ json: {
    company_name: output.company_name || '',
    full_name: output.full_name || '',
    job_title: output.job_title || '',
    phone_number: output.phone_number || '',
    mobile_number: output.mobile_number || '',
    email: output.email || '',
    website: output.website || '',
    address: output.address || '',
    products: output.products || '',
    other_details: output.other_details || '',
    sales_person_name: sales_person_name,
    remark: remark,
    event_name: event_name,
    quick_notes: quick_notes,
    voice_note: voice_note_text
  }});
}

return processedItems;

// Clean and format phone numbers for WhatsApp API
function cleanForWhatsApp(num) {
  if (!num) return '';
  let cleaned = String(num).replace(/[^0-9]/g, '');
  if (!cleaned || cleaned.length < 5) return '';
  if (cleaned.startsWith('0')) cleaned = cleaned.substring(1);
  if (!cleaned.startsWith('91') || cleaned.length <= 10) {
    cleaned = '91' + cleaned;
  }
  return cleaned.substring(0, 12);
}

const items = $input.all();
const results = [];
for (const item of items) {
  const d = item.json;
  const phoneRaw = d['Phone Number'] || d.phone_number || '';
  const mobileRaw = d['Mobile Number'] || d.mobile_number || '';
  results.push({
    json: {
      phone_number: cleanForWhatsApp(phoneRaw),
      mobile_number: cleanForWhatsApp(mobileRaw),
      email: d['Email Address'] || d.email || '',
      customer_name: d['Customer Name'] || d.full_name || '',
      company_name: d['Company Name'] || d.company_name || '',
      event_name: d['Event'] || d.event_name || 'IMTEX 2026 Bangalore'
    }
  });
}
return results;

